import{_ as i,c as a,a1 as t,o as n}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"Social Engineering","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/8-social-engineering/0-Introduction.md","filePath":"categories/ethical-hacking-labs/8-social-engineering/0-Introduction.md"}'),s={name:"categories/ethical-hacking-labs/8-social-engineering/0-Introduction.md"};function r(o,e,h,c,l,p){return n(),a("div",null,e[0]||(e[0]=[t('<h1 id="social-engineering" tabindex="-1">Social Engineering <a class="header-anchor" href="#social-engineering" aria-label="Permalink to &quot;Social Engineering&quot;">​</a></h1><p>Social engineering is the art of manipulating people so they give up confidential information. The types of information these criminals are seeking can vary, but when individuals are targeted the criminals are usually trying to trick you into giving them your passwords or bank information, or access your computer to secretly install malicious software–that will give them access to your passwords and bank information as well as giving them control over your computer.</p><p><a href="https://community.mcafee.com/t5/Documents/Hacking-the-Human-Operating-System-Raj-Samani/ta-p/550808?attachment-id=6539" target="_blank" rel="noreferrer">McAfee&#39;s whitepaper &quot;Hacking the Humanos Operating System&quot;</a> focuses on the use of social engineering to attack home and business users and finds once again that people are the weakest link. The McAfee report points out that there are many organizations who develop and deliver user awareness programs into their business areas, but the effectiveness of such programs varies, and in some identified cases, even after the security training has been delivered, it has done very little to educate their end users with any valued security awareness to mitigate the threat of the social engineering attack.</p><h2 id="phishing-types" tabindex="-1">Phishing types <a class="header-anchor" href="#phishing-types" aria-label="Permalink to &quot;Phishing types&quot;">​</a></h2><h3 id="vishing" tabindex="-1">Vishing <a class="header-anchor" href="#vishing" aria-label="Permalink to &quot;Vishing&quot;">​</a></h3><p>Vishing refers to phishing done over phone calls. Since voice is used for this type of phishing, it is called vishing → voice + phishing = vishing.</p><p>Considering the ease and enormity of data available in social networks, it is no surprise that phishers communicate confidently over a call in the name of friends, relatives or any related brand, without raising any suspicion.</p><h3 id="smishing" tabindex="-1">Smishing <a class="header-anchor" href="#smishing" aria-label="Permalink to &quot;Smishing&quot;">​</a></h3><p>SMS phishing or SMiShing is one of the easiest types of phishing attacks.</p><p>The user is targeted by using SMS alerts.</p><p>In SMiShing, users may receive a fake DM or fake order detail with a cancellation link.</p><p>The link would actually be a fake page designed to gather personal details.</p><h3 id="search-engine-phishing" tabindex="-1">Search Engine Phishing <a class="header-anchor" href="#search-engine-phishing" aria-label="Permalink to &quot;Search Engine Phishing&quot;">​</a></h3><p>Search engine phishing is the type of phishing that refers to the creation of a fake webpage for targeting specific keywords and waiting for the searcher to land on the fake webpage.</p><p>Once a searcher clicks on the page link, s/he will never recognize that s/he is hooked until it is too late.</p><h3 id="spear-phishing" tabindex="-1">Spear Phishing <a class="header-anchor" href="#spear-phishing" aria-label="Permalink to &quot;Spear Phishing&quot;">​</a></h3><p>Unlike traditional phishing – which involves sending emails to millions of unknown users – spear phishing is typically targeted in nature, and the emails are carefully designed to target a particular user.</p><p>These attacks have a greater risk because phishers do a complete social profile research about the user and their organization – through their social media profile and company website.</p><p>Out of the different types of phishing attacks, Spear phishing is the most commonly used type of phishing attack – on individual users as well as organizations.</p><h3 id="whaling" tabindex="-1">Whaling <a class="header-anchor" href="#whaling" aria-label="Permalink to &quot;Whaling&quot;">​</a></h3><p>Whaling is not very different from spear phishing, but the targeted group becomes more specific and confined in this type of phishing attack.</p><p>This technique targets C-suite posts like CEO, CFO, COO – or any other senior management positions – who are considered to be big players in the information chain of any organization, commonly known as “whales” in phishing terms.</p><p>Technology, banking, and healthcare are the most targeted sectors for phishing attacks. This is because of two main factors: a huge number of users and higher dependency on data.</p><p>Links:</p><p><a href="https://youtu.be/D5kg3jZ0Kcw" target="_blank" rel="noreferrer">https://youtu.be/D5kg3jZ0Kcw</a></p><p><a href="https://www.webroot.com/us/en/resources/tips-articles/what-is-social-engineering" target="_blank" rel="noreferrer">https://www.webroot.com/us/en/resources/tips-articles/what-is-social-engineering</a></p><p><a href="https://community.mcafee.com/t5/Documents/Hacking-the-Human-Operating-System-Raj-Samani/ta-p/550808?attachment-id=6539" target="_blank" rel="noreferrer">https://community.mcafee.com/t5/Documents/Hacking-the-Human-Operating-System-Raj-Samani/ta-p/550808?attachment-id=6539</a></p><p><a href="https://www.csoonline.com/article/2124681/what-is-social-engineering.html" target="_blank" rel="noreferrer">https://www.csoonline.com/article/2124681/what-is-social-engineering.html</a></p><p><a href="https://blog.syscloud.com/types-of-phishing/" target="_blank" rel="noreferrer">https://blog.syscloud.com/types-of-phishing/</a></p>',29)]))}const u=i(s,[["render",r]]);export{d as __pageData,u as default};
